1	/**
2	 * Tool-Usage Observer — Phase 1：observation 寫入層
3	 *
4	 * 把 tool 使用落盤成結構化 JSONL（observations.jsonl），供 Phase 2 的
5	 * instinct-evolve analyzer 萃取 skill。本檔是「唯一寫入收斂點」：負責
6	 * schema 組裝、脫敏、截斷、size cap、fail-silent，零業務邏輯外洩。
7	 *
8	 * 雙層訊號（兩條 Provider 路徑都收）：
9	 *  - Tier A（seq）：sessionManager 在 tool_call_update 寫，僅 ACP 路徑。
10	 *    只有 name+status+precedingTools，且 precedingTools 是「完成順序近似」
11	 *    （ACP 進程外並行跑 tool，update 到達序 ≠ 發起序）→ 標
12	 *    precedingToolsSemantics:"completion-order-approx"，避免 Phase 2 誤當發起序。
13	 *  - Tier B（rich）：tool-loop 在 executeToolCalls 內寫，僅 DirectProvider。
14	 *    含 args（脫敏）+output（截斷）+isError，precedingTools 為 loop-local 發起序
15	 *    → precedingToolsSemantics:"exec-order"。
16	 *
17	 * fail-silent：寫入失敗只 console.error，絕不向上拋（不得中斷 tool loop / session）。
18	 */
19	import { appendFileSync, existsSync, mkdirSync, statSync } from "node:fs";
20	import { dirname, join } from "node:path";
21	import { config } from "./config.js";
22	
23	// ─── 常數 ────────────────────────────────────────────────────────────────
24	
25	/** turn 邊界哨兵。resetTurn 時 push，Phase 2 analyzer 見此即切斷 combo（不跨 turn）。 */
26	export const TURN_MARKER = " TURN ";
27	
28	/** precedingTools 滾動長度上限（含 turn marker，避免長駐 session 無界增長）。 */
29	const MAX_RECENT = 8;
30	
31	/** observations.jsonl 體積上限；超過即安靜停寫（Phase 1 不滾動，Phase 2 補 rotate）。 */
32	const OBS_MAX_BYTES = 32 * 1024 * 1024;
33	
34	/** 單筆 rich output 的 hard cap。observer 自帶，不借 tool-loop 的 maxToolResultChars（非 local 時為 undefined=不截斷）。 */
35	const OBS_MAX_OUTPUT_CHARS = 8 * 1024;
36	
37	/** 脫敏：key 名命中即把值替為 [REDACTED]。 */
38	const SECRET_KEY_RE = /token|key|secret|password|authorization|auth/i;
39	
40	/** observations.jsonl 預設路徑（測試可用 BRIDGE_OBSERVATIONS_PATH 覆蓋）。 */
41	export const OBSERVATIONS_PATH = join(config.memoryDir, "observations.jsonl");
42	
43	// ─── 型別 ────────────────────────────────────────────────────────────────
44	
45	export type PrecedingSemantics = "exec-order" | "completion-order-approx";
46	
47	export interface Observation {
48	  ts: string;
49	  source: "seq" | "rich";
50	  name: string;
51	  sessionId: string;
52	  chatId?: number;
53	  precedingTools: string[];
54	  precedingToolsSemantics: PrecedingSemantics;
55	  /** seq only */
56	  status?: "completed" | "failed";
57	  /** rich only — 經 redactArgs。 */
58	  args?: Record<string, unknown>;
59	  /** rich only — 經截斷。 */
60	  output?: string;
61	  /** rich only */
62	  isError?: boolean;
63	}
64	
65	export interface SeqObservationInput {
66	  name: string;
67	  status: "completed" | "failed";
68	  sessionId: string;
69	  chatId?: number;
70	  precedingTools: string[];
71	}
72	
73	export interface RichObservationInput {
74	  name: string;
75	  args: Record<string, unknown>;
76	  output: string;
77	  isError: boolean;
78	  sessionId: string;
79	  chatId?: number;
80	  precedingTools: string[];
81	}
82	
83	// ─── 內部工具 ─────────────────────────────────────────────────────────────
84	
85	/** 寫入路徑：測試覆蓋優先，否則用 config.memoryDir 下的預設檔。 */
86	function observationsPath(): string {
87	  return process.env.BRIDGE_OBSERVATIONS_PATH || OBSERVATIONS_PATH;
88	}
89	
90	/** shell command 內嵌 secret 的 best-effort 清除（不合約化、不宣稱無洩漏）。 */
91	function scrubSecretsInText(s: string): string {
92	  return s
93	    .replace(/Bearer\s+\S+/gi, "Bearer [REDACTED]")
94	    .replace(/-p\s*\S+/g, "-p[REDACTED]")
95	    .replace(/\b(api[_-]?key|key|token|secret|password)\s*=\s*\S+/gi, "$1=[REDACTED]");
96	}
97	
98	/**
99	 * 脫敏 args（best-effort，export 供測試）。
100	 * - key 名命中 SECRET_KEY_RE → 值替為 [REDACTED]。
101	 * - command 字串值（shell tool 最高頻）→ 額外跑 value-level regex。
102	 * ⚠️ 已知限制：擋不住「值是 secret 但 key 名無關鍵字」者。不寫成綠燈契約。
103	 */
104	export function redactArgs(args: Record<string, unknown>): Record<string, unknown> {
105	  const out: Record<string, unknown> = {};
106	  for (const [k, v] of Object.entries(args)) {
107	    if (SECRET_KEY_RE.test(k)) {
108	      out[k] = "[REDACTED]";
109	    } else if (k === "command" && typeof v === "string") {
110	      out[k] = scrubSecretsInText(v);
111	    } else {
112	      out[k] = v;
113	    }
114	  }
115	  return out;
116	}
117	
118	function truncate(s: string, max: number): string {
119	  return s.length > max ? s.slice(0, max) + `\n...[truncated ${s.length - max} chars]` : s;
120	}
121	
122	/**
123	 * 唯一落盤點。整段 try/catch 包覆（涵蓋 schema 組裝/脫敏/同步寫入的所有拋錯），
124	 * fail-silent。沿用 event-log.ts 的 mkdirSync+appendFileSync 範式。
125	 */
126	function appendObservation(obs: Observation): void {
127	  try {
128	    const target = observationsPath();
129	    // size cap：超過上限安靜停寫（不滾動、不刪除）
130	    if (existsSync(target) && statSync(target).size > OBS_MAX_BYTES) return;
131	    const dir = dirname(target);
132	    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
133	    appendFileSync(target, JSON.stringify(obs) + "\n", "utf-8");
134	  } catch (err) {
135	    // observation 是旁路訊號，寫入失敗絕不影響主流程
136	    console.error("[tool-observer] failed to write observation:", err);
137	  }
138	}
139	
140	// ─── 公開 API ─────────────────────────────────────────────────────────────
141	
142	/** Tier A（ACP 路徑序列訊號）。fire-and-forget。 */
143	export function recordSeqObservation(input: SeqObservationInput): void {
144	  appendObservation({
145	    ts: new Date().toISOString(),
146	    source: "seq",
147	    name: input.name,
148	    status: input.status,
149	    sessionId: input.sessionId,
150	    chatId: input.chatId,
151	    precedingTools: input.precedingTools,
152	    precedingToolsSemantics: "completion-order-approx",
153	  });
154	}
155	
156	/** Tier B（DirectProvider rich 訊號）。fire-and-forget。 */
157	export function recordRichObservation(input: RichObservationInput): void {
158	  appendObservation({
159	    ts: new Date().toISOString(),
160	    source: "rich",
161	    name: input.name,
162	    sessionId: input.sessionId,
163	    chatId: input.chatId,
164	    precedingTools: input.precedingTools,
165	    precedingToolsSemantics: "exec-order",
166	    args: redactArgs(input.args),
167	    output: truncate(input.output, OBS_MAX_OUTPUT_CHARS),
168	    isError: input.isError,
169	  });
170	}
171	
172	/**
173	 * 把工具名（或 turn marker）push 進 rolling 序列並維持上限。
174	 * 兩條路徑共用此 helper 保證 cap 一致（避免無界增長）。
175	 */
176	export function appendToolName(recent: string[], name: string, max = MAX_RECENT): string[] {
177	  recent.push(name);
178	  const overflow = recent.length - max;
179	  if (overflow > 0) recent.splice(0, overflow);
180	  return recent;
181	}
182

