1	// Tool-Usage Observer (Phase 1) smoke.
2	//
3	// Covers BC-1a / BC-2 / BC-5 / BC-6 / BC-7 / BC-8 from
4	// .claude-loop/artifacts/P1-design-spec.md §3.
5	//   BC-1  (Direct→只 rich 不 seq)：rich 側由 BC-1a 覆蓋；no-seq-for-direct 由 seq 寫入點
6	//         的 `activeProvider==="acp"` 守衛 by-construction 保證（applyUpdate 為 private，
7	//         不在 dist 易測範圍，故此處測守衛所依賴的 record/序列單元）。
8	//   BC-3/BC-4 為 Phase 2（analyzer），本輪不實作。
9	//
10	// Run: node scripts/check-tool-observer.mjs
11	// Uses compiled dist/* — run `npx tsc` first.
12	
13	import { writeFileSync, readFileSync, existsSync, mkdirSync, rmSync } from "node:fs";
14	import { tmpdir } from "node:os";
15	import { join } from "node:path";
16	
17	// ── 必須在 import dist 之前設好 env ──────────────────────────────────────
18	// RTK_ENABLED 是 tool-loop 的 module-level const（import 時定值）→ 先開。
19	process.env.RTK_SHELL_REWRITE = "1";
20	const OBS_DIR = join(tmpdir(), "tko-smoke");
21	if (existsSync(OBS_DIR)) rmSync(OBS_DIR, { recursive: true, force: true });
22	mkdirSync(OBS_DIR, { recursive: true });
23	const OBS_PATH = join(OBS_DIR, "observations.jsonl");
24	process.env.BRIDGE_OBSERVATIONS_PATH = OBS_PATH;
25	
26	const { redactArgs, recordSeqObservation, appendToolName, TURN_MARKER } =
27	  await import("../dist/tool-observer.js");
28	const { runToolLoop } = await import("../dist/provider/tool-loop.js");
29	
30	// ── harness ──────────────────────────────────────────────────────────────
31	const results = [];
32	const ok = (n) => { results.push({ n, pass: true }); console.log(`[PASS] ${n}`); };
33	const fail = (n, d) => { results.push({ n, pass: false, d }); console.error(`[FAIL] ${n}: ${d}`); };
34	
35	function resetObs() { writeFileSync(OBS_PATH, "", "utf-8"); }
36	function readObs() {
37	  if (!existsSync(OBS_PATH)) return [];
38	  return readFileSync(OBS_PATH, "utf-8").trim().split("\n").filter(Boolean).map((l) => JSON.parse(l));
39	}
40	
41	const tc = (name, args = "{}") => ({ id: `${name}-id`, type: "function", function: { name, arguments: args } });
42	
43	// mock LlmAdapter：依 script 逐 iteration 回 tool_calls，最後回無 tool_calls 收尾。
44	function mockAdapter(script) {
45	  let i = 0;
46	  return {
47	    async chat() {
48	      const step = script[i++];
49	      if (!step || step.stop) return { message: { role: "assistant", content: "done" }, stopReason: "stop" };
50	      return { message: { role: "assistant", content: "", tool_calls: step.tool_calls }, stopReason: "tool_calls" };
51	    },
52	  };
53	}
54	const mockPool = { async callTool(name) { return { content: [{ type: "text", text: `out:${name}` }], isError: false }; } };
55	
56	// ── BC-6：redactArgs ───────────────────────────────────────────────────────
57	{
58	  const r = redactArgs({ command: "ls /home/user", apiKey: "sk-xxx", token: "abc", authorization: "Bearer y" });
59	  if (r.apiKey === "[REDACTED]" && r.token === "[REDACTED]" && r.authorization === "[REDACTED]" && r.command === "ls /home/user") {
60	    ok("BC-6 key-name blacklist redacts secrets, keeps path");
61	  } else fail("BC-6 key-name blacklist", JSON.stringify(r));
62	
63	  const r2 = redactArgs({ command: "curl -H 'Authorization: Bearer sk-live-123' https://x" });
64	  if (typeof r2.command === "string" && r2.command.includes("[REDACTED]") && !r2.command.includes("sk-live-123")) {
65	    ok("BC-6 shell command value-level scrub");
66	  } else fail("BC-6 shell scrub", JSON.stringify(r2));
67	}
68	
69	// ── BC-5：fail-silent（寫入失敗不拋）─────────────────────────────────────────
70	{
71	  const good = process.env.BRIDGE_OBSERVATIONS_PATH;
72	  // 指向一個「目錄」當檔案路徑 → appendFileSync 應 EISDIR；observer 必須吞掉。
73	  process.env.BRIDGE_OBSERVATIONS_PATH = OBS_DIR;
74	  let threw = false;
75	  try {
76	    const ret = recordSeqObservation({ name: "x", status: "completed", sessionId: "s", precedingTools: [] });
77	    if (ret !== undefined) threw = true; // 應回 void
78	  } catch { threw = true; }
79	  process.env.BRIDGE_OBSERVATIONS_PATH = good;
80	  if (!threw) ok("BC-5 fail-silent: write error neither throws nor returns value");
81	  else fail("BC-5 fail-silent", "recordSeqObservation threw or returned non-void on bad path");
82	}
83	
84	// ── BC-1a：Tier B precedingTools = loop-local 發起序（非進 loop 前快照）──────────
85	{
86	  resetObs();
87	  const messages = [];
88	  await runToolLoop(
89	    mockAdapter([{ tool_calls: [tc("toolA")] }, { tool_calls: [tc("toolB")] }, { stop: true }]),
90	    mockPool, messages, [], { observe: { sessionId: "bc1a" } },
91	  );
92	  const obs = readObs();
93	  const a = obs.find((o) => o.name === "toolA");
94	  const b = obs.find((o) => o.name === "toolB");
95	  if (a && b && a.source === "rich" && b.source === "rich" &&
96	      a.precedingTools.length === 0 &&
97	      b.precedingTools.includes("toolA") &&
98	      b.precedingToolsSemantics === "exec-order") {
99	    ok("BC-1a rich precedingTools reflect exec-order (toolA precedes toolB)");
100	  } else fail("BC-1a exec-order precedingTools", JSON.stringify(obs));
101	}
102	
103	// ── BC-7：rich 記 RTK rewrite 前的原始 args.command ─────────────────────────
104	{
105	  resetObs();
106	  const messages = [];
107	  await runToolLoop(
108	    mockAdapter([{ tool_calls: [tc("shell", JSON.stringify({ command: "git status" }))] }, { stop: true }]),
109	    mockPool, messages, [], { observe: { sessionId: "bc7" } },
110	  );
111	  const obs = readObs();
112	  const shell = obs.find((o) => o.name === "shell");
113	  if (shell && shell.args && shell.args.command === "git status") {
114	    ok("BC-7 rich records pre-RTK original command (not 'rtk git status')");
115	  } else fail("BC-7 pre-RTK snapshot", JSON.stringify(obs));
116	}
117	
118	// ── BC-2：seq schema（completion-order-approx、無 args/output）────────────────
119	{
120	  resetObs();
121	  recordSeqObservation({ name: "grep", status: "completed", sessionId: "acp1", chatId: 5, precedingTools: ["glob"] });
122	  const obs = readObs();
123	  const o = obs[0];
124	  if (obs.length === 1 && o.source === "seq" && o.name === "grep" && o.status === "completed" &&
125	      o.precedingToolsSemantics === "completion-order-approx" &&
126	      o.args === undefined && o.output === undefined && o.isError === undefined) {
127	    ok("BC-2 seq observation: completion-order-approx, no args/output");
128	  } else fail("BC-2 seq schema", JSON.stringify(obs));
129	}
130	
131	// ── BC-8：跨 turn 不污染 combo（turn marker 介於兩 turn 工具名之間）────────────
132	{
133	  // 模擬 sessionManager 對 _recentToolNames 的維護：tool_call push、resetTurn push marker。
134	  let recent = [];
135	  recent = appendToolName(recent, "toolA");          // turn1 tool
136	  if (recent.length) recent = appendToolName(recent, TURN_MARKER); // resetTurn（不清空）
137	  recent = appendToolName(recent, "toolB");          // turn2 tool
138	  const iA = recent.indexOf("toolA");
139	  const iM = recent.indexOf(TURN_MARKER);
140	  const iB = recent.indexOf("toolB");
141	  if (iA >= 0 && iM > iA && iB > iM) {
142	    ok("BC-8 turn marker separates cross-turn tools (toolA < TURN < toolB)");
143	  } else fail("BC-8 turn marker", JSON.stringify(recent));
144	}
145	
146	// ── 收尾 ───────────────────────────────────────────────────────────────────
147	rmSync(OBS_DIR, { recursive: true, force: true });
148	const failed = results.filter((r) => !r.pass);
149	console.log(`\n${results.length - failed.length}/${results.length} passed`);
150	process.exit(failed.length ? 1 : 0);
151
